def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    sentences = []
    for subject, triples_list in subject_map.items():
        # Handle special cases with natural language patterns first
        processed_predicates = set()

        # Mayor: "The mayor of [subject] is [obj]."
        for predicate, obj in triples_list:
            if predicate == "mayor":
                sentences.append(f"{subject} has a mayor of {obj}.")
                processed_predicates.add("mayor")
                break

        # Leader: "The leader of [subject] is [obj]."
        for predicate, obj in triples_list:
            if predicate == "leader":
                sentences.append(f"{subject} has a leader of {obj}.")
                processed_predicates.add("leader")
                break

        # Language: "[obj] is spoken in [subject]."
        for predicate, obj in triples_list:
            if predicate == "language":
                sentences.append(f"{subject} speaks {obj}.")
                processed_predicates.add("language")
                break

        # Location identifier: "[subject] location identifier is [obj]."
        for predicate, obj in triples_list:
            if predicate == "locationIdentifier":
                sentences.append(f"{subject} location identifier is {obj}.")
                processed_predicates.add("locationIdentifier")
                break

        # IATA/ICAO identifiers: use direct "is" structure
        for predicate, obj in triples_list:
            if predicate == "iataLocationIdentifier":
                sentences.append(f"{subject} IATA identifier is {obj}.")
                processed_predicates.add("iataLocationIdentifier")
            elif predicate == "icaoLocationIdentifier":
                sentences.append(f"{subject} ICAO identifier is {obj}.")
                processed_predicates.add("icaoLocationIdentifier")

        # Build remaining details without the processed ones
        base = subject
        details = []
        for predicate, obj in triples_list:
            if predicate in processed_predicates:
                continue

            if predicate == "cityServed":
                details.append(f"serves the city of {obj}")
            elif predicate == "isPartOf":
                details.append(f"is part of {obj}")
            elif predicate == "operatingOrganisation":
                details.append(f"is operated by {obj}")
            elif predicate == "location":
                details.append(f"is located in {obj}")
            elif predicate == "elevationAboveTheSeaLevel":
                details.append(f"has an elevation of {obj} metres above sea level")
            elif predicate == "runwayLength":
                details.append(f"has a runway length of {obj} metres")
            elif predicate == "country":
                details.append(f"is located in {obj}")
            elif predicate == "capital":
                details.append(f"has a capital of {obj}")
            elif predicate == "owner":
                details.append(f"is owned by {obj}")
            elif predicate == "1stRunwayLengthFeet":
                details.append(f"has a first runway length of {obj} feet")
            elif predicate == "1stRunwaySurfaceType":
                details.append(f"has a first runway surface type of {obj}")
            elif predicate == "3rdRunwayLengthFeet":
                details.append(f"has a third runway length of {obj} feet")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                details.append(f"has an elevation of {obj} feet above sea level")
            elif predicate == "nativeName":
                details.append(f"has a native name of {obj}")
            elif predicate == "leaderParty":
                details.append(f"has a leader party of {obj}")
            else:
                details.append(f"has a {predicate} of {obj}")

        if details:
            base += " " + ", ".join(details)
            sentences.append(base + ".")

    # Join sentences with appropriate connectors
    if len(sentences) == 1:
        return sentences[0]
    else:
        # Create a complex sentence by connecting the sentences with subordinating conjunctions
        sentence = sentences[0]
        for s in sentences[1:]:
            sentence += ", which " + s
        return sentence + "."

